42	// store stores the cluster state needed by the provisioner and allows to update it from the events.
43	type store struct {
44		// gateways is a map of all Gateway resources in the cluster. Used on startup to determine
45		// which nginx resources aren't tied to any Gateways and need to be cleaned up.
46		gateways map[types.NamespacedName]*gatewayv1.Gateway
47		// nginxResources is a map of Gateway NamespacedNames and their associated nginx resources.
48		nginxResources map[types.NamespacedName]*NginxResources
49	
50		// deletingGateways is a set of Gateways that are currently being deleted.
51		deletingGateways sync.Map
52	
53		dockerSecretNames  map[string]struct{}
54		agentTLSSecretName string
55	
56		// NGINX Plus secrets
57		jwtSecretName       string
58		caSecretName        string
59		clientSSLSecretName string
60	
61		// NGINX One Dataplane key secret
62		dataplaneKeySecretName string
