67	func newStore(
68		dockerSecretNames []string,
69		agentTLSSecretName,
70		jwtSecretName,
71		caSecretName,
72		clientSSLSecretName,
73		dataplaneKeySecretName string,
74	) *store {
75		dockerSecretNamesMap := make(map[string]struct{})
76		for _, name := range dockerSecretNames {
77			dockerSecretNamesMap[name] = struct{}{}
78		}
79	
80		return &store{
81			gateways:               make(map[types.NamespacedName]*gatewayv1.Gateway),
82			nginxResources:         make(map[types.NamespacedName]*NginxResources),
83			deletingGateways:       sync.Map{},
84			dockerSecretNames:      dockerSecretNamesMap,
85			agentTLSSecretName:     agentTLSSecretName,
86			jwtSecretName:          jwtSecretName,
87			caSecretName:           caSecretName,
88			clientSSLSecretName:    clientSSLSecretName,
89			dataplaneKeySecretName: dataplaneKeySecretName,
90		}
91	}
92	
93	func (s *store) updateGateway(obj *gatewayv1.Gateway) {
94		s.lock.Lock()
95		defer s.lock.Unlock()
96	
97		s.gateways[client.ObjectKeyFromObject(obj)] = obj
98	}
99	
100	func (s *store) deleteGateway(nsName types.NamespacedName) {
101		s.lock.Lock()
102		defer s.lock.Unlock()
103	
104		delete(s.gateways, nsName)
105	}
106	
107	func (s *store) getGateway(nsName types.NamespacedName) *gatewayv1.Gateway {
108		s.lock.RLock()
109		defer s.lock.RUnlock()
110	
111		return s.gateways[nsName]
112	}
113	
114	func (s *store) getGateways() map[types.NamespacedName]*gatewayv1.Gateway {
115		s.lock.RLock()
116		defer s.lock.RUnlock()
117	
118		return s.gateways
119	}
120	
121	// registerResourceInGatewayConfig adds or updates the provided resource in the tracking map.
122	// If the object being updated is the Gateway, check if anything that we care about changed. This ensures that
123	// we don't attempt to update nginx resources when the main event handler triggers this call with an unrelated event
124	// (like a Route update) that shouldn't result in nginx resource changes.
125	//
126	// The Gateway case returns whether anything we care about changed; all other resource types always
127	// report a change.
128	func (s *store) registerResourceInGatewayConfig(gatewayNSName types.NamespacedName, object any) bool {
129		s.lock.Lock()
130		defer s.lock.Unlock()
131	
132		switch obj := object.(type) {
133		case *graph.Gateway:
134			if cfg, ok := s.nginxResources[gatewayNSName]; ok {
135				changed := gatewayChanged(cfg.Gateway, obj)
136				cfg.Gateway = obj
137				return changed
138			}
139			s.nginxResources[gatewayNSName] = &NginxResources{Gateway: obj}
140		case *appsv1.Deployment:
141			s.getOrCreateNginxResources(gatewayNSName).Deployment = obj.ObjectMeta
142		case *autoscalingv2.HorizontalPodAutoscaler:
143			s.getOrCreateNginxResources(gatewayNSName).HPA = obj.ObjectMeta
144		case *policyv1.PodDisruptionBudget:
145			s.getOrCreateNginxResources(gatewayNSName).PDB = obj.ObjectMeta
146		case *appsv1.DaemonSet:
147			s.getOrCreateNginxResources(gatewayNSName).DaemonSet = obj.ObjectMeta
148		case *corev1.Service:
149			s.getOrCreateNginxResources(gatewayNSName).Service = obj.ObjectMeta
150		case *corev1.ServiceAccount:
151			s.getOrCreateNginxResources(gatewayNSName).ServiceAccount = obj.ObjectMeta
152		case *rbacv1.Role:
153			s.getOrCreateNginxResources(gatewayNSName).Role = obj.ObjectMeta
154		case *rbacv1.RoleBinding:
155			s.getOrCreateNginxResources(gatewayNSName).RoleBinding = obj.ObjectMeta
156		case *corev1.ConfigMap:
157			s.registerConfigMapInGatewayConfig(obj, gatewayNSName)
158		case *corev1.Secret:
159			s.registerSecretInGatewayConfig(obj, gatewayNSName)
160		}
161	
162		return true
163	}
164	
165	// getOrCreateNginxResources returns the NginxResources tracked for the given Gateway, creating and
166	// storing an empty entry first if none exists yet. Callers must hold s.lock.
167	func (s *store) getOrCreateNginxResources(gatewayNSName types.NamespacedName) *NginxResources {
168		cfg, ok := s.nginxResources[gatewayNSName]
169		if !ok {
170			cfg = &NginxResources{}
171			s.nginxResources[gatewayNSName] = cfg
172		}
173	
174		return cfg
175	}
176	
177	func (s *store) registerConfigMapInGatewayConfig(obj *corev1.ConfigMap, gatewayNSName types.NamespacedName) {
178		if cfg, ok := s.nginxResources[gatewayNSName]; !ok {
179			if strings.HasSuffix(obj.GetName(), nginxIncludesConfigMapNameSuffix) {
180				s.nginxResources[gatewayNSName] = &NginxResources{
181					BootstrapConfigMap: obj.ObjectMeta,
182				}
183			} else if strings.HasSuffix(obj.GetName(), nginxAgentConfigMapNameSuffix) {
184				s.nginxResources[gatewayNSName] = &NginxResources{
185					AgentConfigMap: obj.ObjectMeta,
186				}
187			}
188		} else {
189			if strings.HasSuffix(obj.GetName(), nginxIncludesConfigMapNameSuffix) {
190				cfg.BootstrapConfigMap = obj.ObjectMeta
191			} else if strings.HasSuffix(obj.GetName(), nginxAgentConfigMapNameSuffix) {
192				cfg.AgentConfigMap = obj.ObjectMeta
193			}
194		}
195	}
196	
197	// hasSuffix reports whether str ends with a non-empty suffix.
198	func hasSuffix(str, suffix string) bool {
199		return suffix != "" && strings.HasSuffix(str, suffix)
200	}
201	
202	// assignNamedSecret sets the matching named-secret field on cfg from obj and
203	// reports whether obj matched one of the configured named secrets.
204	// Callers must hold s.lock.
205	func (s *store) assignNamedSecret(cfg *NginxResources, obj *corev1.Secret) bool {
206		switch name := obj.GetName(); {
207		case hasSuffix(name, s.agentTLSSecretName):
208			cfg.AgentTLSSecret = obj.ObjectMeta
209		case hasSuffix(name, s.jwtSecretName):
210			cfg.PlusJWTSecret = obj.ObjectMeta
211		case hasSuffix(name, s.caSecretName):
212			cfg.PlusCASecret = obj.ObjectMeta
213		case hasSuffix(name, s.clientSSLSecretName):
214			cfg.PlusClientSSLSecret = obj.ObjectMeta
215		case hasSuffix(name, s.dataplaneKeySecretName):
216			cfg.DataplaneKeySecret = obj.ObjectMeta
217		default:
218			return false
219		}
220	
221		return true
222	}
223	
224	func (s *store) registerSecretInGatewayConfig(obj *corev1.Secret, gatewayNSName types.NamespacedName) {
225		if cfg, ok := s.nginxResources[gatewayNSName]; ok {
226			s.assignNamedSecret(cfg, obj)
227	
228			for secret := range s.dockerSecretNames {
229				if hasSuffix(obj.GetName(), secret) {
230					if len(cfg.DockerSecrets) == 0 {
231						cfg.DockerSecrets = []metav1.ObjectMeta{obj.ObjectMeta}
232					} else {
233						cfg.DockerSecrets = append(cfg.DockerSecrets, obj.ObjectMeta)
234					}
235				}
236			}
237	
238			return
239		}
240	
241		// No config exists yet for this Gateway: create a fresh entry only when the
242		// Secret matches a configured name. A matching docker secret overwrites the
243		// entry, preserving the original first-match-wins behavior.
244		cfg := &NginxResources{}
245		if s.assignNamedSecret(cfg, obj) {
246			s.nginxResources[gatewayNSName] = cfg
247		}
248	
249		for secret := range s.dockerSecretNames {
250			if hasSuffix(obj.GetName(), secret) {
251				s.nginxResources[gatewayNSName] = &NginxResources{
252					DockerSecrets: []metav1.ObjectMeta{obj.ObjectMeta},
253				}
254				break
255			}
256		}
257	}
258	
259	func gatewayChanged(original, updated *graph.Gateway) bool {
260		if original == nil {
261			return true
262		}
263	
264		if original.Valid != updated.Valid {
265			return true
266		}
267	
268		if !reflect.DeepEqual(original.Source, updated.Source) {
269			return true
270		}
271	
272		if !reflect.DeepEqual(original.EffectiveNginxProxy, updated.EffectiveNginxProxy) {
273			return true
274		}
275	
276		// Check if the effective set of listeners changed (e.g., due to ListenerSet additions/removals).
277		// We compare port/protocol pairs since those determine the Service and container ports.
278		return listenersChanged(original.Listeners, updated.Listeners)
279	}
280	
281	// listenersChanged returns true if the set of listener names, ports, protocols, or hostnames
282	// has changed. Order is intentionally ignored: the provisioner only cares about which ports
283	// need to be exposed, not their order. Listener conflict resolution is handled upstream in
284	// the graph builder and does not affect provisioned resources.
285	func listenersChanged(original, updated []*graph.Listener) bool {
286		if len(original) != len(updated) {
287			return true
288		}
289	
290		type listenerKey struct {
291			Name     string
292			Protocol gatewayv1.ProtocolType
293			Hostname string
294			Port     gatewayv1.PortNumber
295		}
296	
297		buildSet := func(listeners []*graph.Listener) map[listenerKey]struct{} {
298			set := make(map[listenerKey]struct{}, len(listeners))
299			for _, l := range listeners {
300				hostname := ""
301				if l.Source.Hostname != nil {
302					hostname = string(*l.Source.Hostname)
303				}
304				key := listenerKey{
305					Name:     l.Name,
306					Port:     l.Source.Port,
307					Protocol: l.Source.Protocol,
308					Hostname: hostname,
309				}
310				set[key] = struct{}{}
311			}
312			return set
313		}
314	
315		return !reflect.DeepEqual(buildSet(original), buildSet(updated))
316	}
317	
318	func (s *store) getNginxResourcesForGateway(nsName types.NamespacedName) *NginxResources {
319		s.lock.RLock()
320		defer s.lock.RUnlock()
321	
322		return s.nginxResources[nsName]
323	}
324	
325	func (s *store) deleteResourcesForGateway(nsName types.NamespacedName) {
326		s.lock.Lock()
327		defer s.lock.Unlock()
328	
329		delete(s.nginxResources, nsName)
330	}
331	
332	func (s *store) gatewayExistsForResource(object client.Object, nsName types.NamespacedName) *graph.Gateway {
333		s.lock.RLock()
334		defer s.lock.RUnlock()
335	
336		for _, resources := range s.nginxResources {
337			if resources.matchesObject(object, nsName) {
338				return resources.Gateway
339			}
340		}
341	
342		return nil
343	}
344	
345	// matchesObject reports whether nsName identifies one of the nginx resources tracked for this
346	// Gateway, dispatching on the concrete type of object.
347	func (r *NginxResources) matchesObject(object client.Object, nsName types.NamespacedName) bool {
348		switch object.(type) {
349		case *appsv1.Deployment:
350			return resourceMatches(r.Deployment, nsName)
351		case *autoscalingv2.HorizontalPodAutoscaler:
352			return resourceMatches(r.HPA, nsName)
353		case *policyv1.PodDisruptionBudget:
354			return resourceMatches(r.PDB, nsName)
355		case *appsv1.DaemonSet:
356			return resourceMatches(r.DaemonSet, nsName)
357		case *corev1.Service:
358			return resourceMatches(r.Service, nsName)
359		case *corev1.ServiceAccount:
360			return resourceMatches(r.ServiceAccount, nsName)
361		case *rbacv1.Role:
362			return resourceMatches(r.Role, nsName)
363		case *rbacv1.RoleBinding:
364			return resourceMatches(r.RoleBinding, nsName)
365		case *corev1.ConfigMap:
366			return resourceMatches(r.BootstrapConfigMap, nsName) || resourceMatches(r.AgentConfigMap, nsName)
367		case *corev1.Secret:
368			return secretResourceMatches(r, nsName)
369		}
370	
371		return false
372	}
373	
374	func secretResourceMatches(resources *NginxResources, nsName types.NamespacedName) bool {
375		if resourceMatches(resources.AgentTLSSecret, nsName) {
376			return true
377		}
378	
379		for _, secret := range resources.DockerSecrets {
380			if resourceMatches(secret, nsName) {
381				return true
382			}
383		}
384	
385		if resourceMatches(resources.PlusJWTSecret, nsName) {
386			return true
387		}
388	
389		if resourceMatches(resources.PlusClientSSLSecret, nsName) {
390			return true
391		}
392	
393		if resourceMatches(resources.DataplaneKeySecret, nsName) {
394			return true
395		}
396	
397		return resourceMatches(resources.PlusCASecret, nsName)
398	}
399	
400	func resourceMatches(objMeta metav1.ObjectMeta, nsName types.NamespacedName) bool {
401		return objMeta.GetName() == nsName.Name && objMeta.GetNamespace() == nsName.Namespace
402	}
403	
404	func (s *store) getResourceVersionForObject(gatewayNSName types.NamespacedName, object client.Object) string {
405		s.lock.RLock()
406		defer s.lock.RUnlock()
407	
408		resources, exists := s.nginxResources[gatewayNSName]
409		if !exists {
410			return ""
411		}
412	
413		switch obj := object.(type) {
414		case *appsv1.Deployment:
415			return resourceVersionIfNameMatches(resources.Deployment, obj.GetName())
416		case *autoscalingv2.HorizontalPodAutoscaler:
417			return resourceVersionIfNameMatches(resources.HPA, obj.GetName())
418		case *policyv1.PodDisruptionBudget:
419			return resourceVersionIfNameMatches(resources.PDB, obj.GetName())
420		case *appsv1.DaemonSet:
421			return resourceVersionIfNameMatches(resources.DaemonSet, obj.GetName())
422		case *corev1.Service:
423			return resourceVersionIfNameMatches(resources.Service, obj.GetName())
424		case *corev1.ServiceAccount:
425			return resourceVersionIfNameMatches(resources.ServiceAccount, obj.GetName())
426		case *rbacv1.Role:
427			return resourceVersionIfNameMatches(resources.Role, obj.GetName())
428		case *rbacv1.RoleBinding:
429			return resourceVersionIfNameMatches(resources.RoleBinding, obj.GetName())
430		case *corev1.ConfigMap:
431			return getResourceVersionForConfigMap(resources, obj)
432		case *corev1.Secret:
433			return getResourceVersionForSecret(resources, obj)
434		}
435	
436		return ""
437	}
438	
439	// resourceVersionIfNameMatches returns the tracked resource's ResourceVersion when its name matches
440	// the provided name, and an empty string otherwise.
441	func resourceVersionIfNameMatches(meta metav1.ObjectMeta, name string) string {
442		if meta.GetName() == name {
443			return meta.GetResourceVersion()
444		}
445	
446		return ""
447	}
448	
449	func getResourceVersionForConfigMap(resources *NginxResources, configmap *corev1.ConfigMap) string {
450		if resources.BootstrapConfigMap.GetName() == configmap.GetName() {
451			return resources.BootstrapConfigMap.GetResourceVersion()
452		}
453		if resources.AgentConfigMap.GetName() == configmap.GetName() {
454			return resources.AgentConfigMap.GetResourceVersion()
455		}
456	
457		return ""
458	}
459	
460	func getResourceVersionForSecret(resources *NginxResources, secret *corev1.Secret) string {
461		if resources.AgentTLSSecret.GetName() == secret.GetName() {
462			return resources.AgentTLSSecret.GetResourceVersion()
463		}
464		for _, dockerSecret := range resources.DockerSecrets {
465			if dockerSecret.GetName() == secret.GetName() {
466				return dockerSecret.GetResourceVersion()
467			}
468		}
469		if resources.PlusJWTSecret.GetName() == secret.GetName() {
470			return resources.PlusJWTSecret.GetResourceVersion()
471		}
472		if resources.PlusClientSSLSecret.GetName() == secret.GetName() {
473			return resources.PlusClientSSLSecret.GetResourceVersion()
474		}
475		if resources.PlusCASecret.GetName() == secret.GetName() {
476			return resources.PlusCASecret.GetResourceVersion()
477		}
478		if resources.DataplaneKeySecret.GetName() == secret.GetName() {
479			return resources.DataplaneKeySecret.GetResourceVersion()
480		}
481	
482		return ""
483	}
484	
485	// markGatewayDeleting marks a Gateway as being deleted.
486	func (s *store) markGatewayDeleting(nsName types.NamespacedName) {
487		s.deletingGateways.Store(nsName, struct{}{})
488	}
489	
490	// isGatewayDeleting checks if a Gateway is marked as being deleted.
491	func (s *store) isGatewayDeleting(nsName types.NamespacedName) bool {
492		_, exists := s.deletingGateways.Load(nsName)
493		return exists
494	}
