1	package provisioner
2	
3	import (
4		"context"
5		"errors"
6		"fmt"
7		"reflect"
8		"strings"
9	
10		"github.com/go-logr/logr"
11		appsv1 "k8s.io/api/apps/v1"
12		autoscalingv2 "k8s.io/api/autoscaling/v2"
13		corev1 "k8s.io/api/core/v1"
14		policyv1 "k8s.io/api/policy/v1"
15		rbacv1 "k8s.io/api/rbac/v1"
16		metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
17		"k8s.io/apimachinery/pkg/labels"
18		"k8s.io/apimachinery/pkg/types"
19		"sigs.k8s.io/controller-runtime/pkg/client"
20		gatewayv1 "sigs.k8s.io/gateway-api/apis/v1"
21	
22		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/status"
23		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/controller"
24		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/events"
25	)
26	
27	// eventHandler ensures each Gateway for the specific GatewayClass has a corresponding Deployment
28	// of NGF configured to use that specific Gateway.
29	//
30	// eventHandler implements events.Handler interface.
31	type eventHandler struct {
32		store         *store
33		provisioner   *NginxProvisioner
34		k8sClient     client.Reader
35		labelSelector labels.Selector
36		// gcName is the GatewayClass name for this control plane.
37		gcName string
38	}
39	
40	func newEventHandler(
41		store *store,
42		provisioner *NginxProvisioner,
43		k8sClient client.Reader,
44		selector metav1.LabelSelector,
45		gcName string,
46	) (*eventHandler, error) {
47		labelSelector, err := metav1.LabelSelectorAsSelector(&selector)
48		if err != nil {
49			return nil, fmt.Errorf("error initializing label selector: %w", err)
50		}
51	
52		return &eventHandler{
53			store:         store,
54			provisioner:   provisioner,
55			k8sClient:     k8sClient,
56			labelSelector: labelSelector,
57			gcName:        gcName,
58		}, nil
59	}
60	
61	func (h *eventHandler) HandleEventBatch(ctx context.Context, logger logr.Logger, batch events.EventBatch) {
62		for _, event := range batch {
63			switch e := event.(type) {
64			case *events.UpsertEvent:
65				if err := h.handleUpsertEvent(ctx, e, logger); err != nil {
66					logger.Error(err, "error handling upsert event")
67				}
68			case *events.DeleteEvent:
69				if err := h.handleDeleteEvent(ctx, e); err != nil {
70					logger.Error(err, "error handling delete event")
71				}
72			default:
73				panic(fmt.Errorf("unknown event type %T", e))
74			}
75		}
76	}
77	
78	func (h *eventHandler) handleUpsertEvent(ctx context.Context, e *events.UpsertEvent, logger logr.Logger) error {
79		switch obj := e.Resource.(type) {
80		case *gatewayv1.Gateway:
81			h.store.updateGateway(obj)
82		case *appsv1.Deployment, *appsv1.DaemonSet, *corev1.ServiceAccount,
83			*corev1.ConfigMap, *rbacv1.Role, *rbacv1.RoleBinding,
84			*autoscalingv2.HorizontalPodAutoscaler, *policyv1.PodDisruptionBudget:
85			if gatewayNSName, ok := h.getGatewayForManagedResource(obj); ok {
86				if err := h.updateOrDeleteResources(ctx, logger, obj, gatewayNSName); err != nil {
87					return fmt.Errorf("error handling resource update: %w", err)
88				}
89			}
90		case *corev1.Service:
91			if gatewayNSName, ok := h.getGatewayForManagedResource(obj); ok {
92				if err := h.updateOrDeleteResources(ctx, logger, obj, gatewayNSName); err != nil {
93					return fmt.Errorf("error handling resource update: %w", err)
94				}
95				h.provisioner.cfg.StatusQueue.Enqueue(&status.QueueObject{
96					Deployment: status.Deployment{
97						NamespacedName: client.ObjectKeyFromObject(obj),
98						GatewayName:    gatewayNSName.Name,
99					},
100					UpdateType:     status.UpdateGateway,
101					GatewayService: obj,
102				})
103			}
104		case *corev1.Secret:
105			if gatewayNSName, ok := h.getGatewayForManagedResource(obj); ok {
106				if err := h.updateOrDeleteResources(ctx, logger, obj, gatewayNSName); err != nil {
107					return fmt.Errorf("error handling resource update: %w", err)
108				}
109			} else if h.provisioner.isUserSecret(obj.GetName()) {
110				if err := h.provisionResourceForAllGateways(ctx, logger, obj); err != nil {
111					return fmt.Errorf("error provisioning resource for all gateways: %w", err)
112				}
113			}
114		default:
115			panic(fmt.Errorf("unknown resource type %T", e.Resource))
116		}
117		return nil
118	}
119	
120	// getGatewayForManagedResource checks if the object is managed by us and returns the
121	// associated Gateway's NamespacedName. Returns false if the object doesn't match our label selector.
122	func (h *eventHandler) getGatewayForManagedResource(obj client.Object) (types.NamespacedName, bool) {
123		objLabels := labels.Set(obj.GetLabels())
124		if !h.labelSelector.Matches(objLabels) {
125			return types.NamespacedName{}, false
126		}
127		gatewayName := objLabels.Get(controller.GatewayLabel)
128		if gatewayName == "" {
129			gatewayName = obj.GetAnnotations()[controller.GatewayLabel]
130		}
131		return types.NamespacedName{Namespace: obj.GetNamespace(), Name: gatewayName}, true
132	}
133	
134	func (h *eventHandler) handleDeleteEvent(ctx context.Context, e *events.DeleteEvent) error {
135		switch e.Type.(type) {
136		case *gatewayv1.Gateway:
137			h.store.markGatewayDeleting(e.NamespacedName)
138	
139			if !h.provisioner.isLeader() {
140				h.provisioner.setResourceToDelete(e.NamespacedName)
141			}
142			h.store.deleteGateway(e.NamespacedName)
143			h.store.deleteResourcesForGateway(e.NamespacedName)
144			deploymentNSName := types.NamespacedName{
145				Name:      controller.CreateNginxResourceName(e.NamespacedName.Name, h.gcName),
146				Namespace: e.NamespacedName.Namespace,
147			}
148			h.provisioner.cfg.DeploymentStore.Remove(deploymentNSName)
149		case *appsv1.Deployment, *appsv1.DaemonSet, *corev1.Service, *corev1.ServiceAccount,
150			*corev1.ConfigMap, *rbacv1.Role, *rbacv1.RoleBinding,
151			*autoscalingv2.HorizontalPodAutoscaler, *policyv1.PodDisruptionBudget:
152	
153			if err := h.reprovisionResources(ctx, e); err != nil {
154				return fmt.Errorf("error re-provisioning nginx resources: %w", err)
155			}
156		case *corev1.Secret:
157			if h.provisioner.isUserSecret(e.NamespacedName.Name) {
158				if err := h.deprovisionSecretsForAllGateways(ctx, e.NamespacedName.Name); err != nil {
159					return fmt.Errorf("error removing secrets: %w", err)
160				}
161			} else {
162				if err := h.reprovisionResources(ctx, e); err != nil {
163					return fmt.Errorf("error re-provisioning nginx resources: %w", err)
164				}
165			}
166		default:
167			panic(fmt.Errorf("unknown resource type %T", e.Type))
168		}
169	
170		return nil
171	}
172	
173	// updateOrDeleteResources ensures that nginx resources are either:
174	// - deleted if the Gateway no longer exists (this is for when the controller first starts up)
175	// - are updated to the proper state in case a user makes a change directly to the resource.
176	func (h *eventHandler) updateOrDeleteResources(
177		ctx context.Context,
178		logger logr.Logger,
179		obj client.Object,
180		gatewayNSName types.NamespacedName,
181	) error {
182		if gw := h.store.getGateway(gatewayNSName); gw == nil {
183			if !h.provisioner.isLeader() {
184				h.provisioner.setResourceToDelete(gatewayNSName)
185				return nil
186			}
187			logger.Info("Gateway not found, associated resources will be garbage collected",
188				"resource", obj.GetName(), "gateway", gatewayNSName)
189			return nil
190		}
191	
192		if !h.hasResourceVersionChanged(ctx, logger, gatewayNSName, obj) {
193			return nil
194		}
195	
196		h.store.registerResourceInGatewayConfig(gatewayNSName, obj)
197		if err := h.provisionResource(ctx, logger, gatewayNSName, obj); err != nil {
198			return fmt.Errorf("error updating nginx resource: %w", err)
199		}
200	
201		return nil
202	}
203	
204	// hasResourceVersionChanged checks if the resource version for the object has changed.
205	// If the resource version is not found in the store, it uses the k8s client to get the current
206	// resource version.
207	func (h *eventHandler) hasResourceVersionChanged(
208		ctx context.Context,
209		logger logr.Logger,
210		gatewayNSName types.NamespacedName,
211		obj client.Object,
212	) bool {
213		objectResourceVersion := obj.GetResourceVersion()
214		storeResourceVersion := h.store.getResourceVersionForObject(gatewayNSName, obj)
215		if storeResourceVersion == "" {
216			storeObject, ok := obj.DeepCopyObject().(client.Object)
217			if ok {
218				getError := h.k8sClient.Get(ctx, client.ObjectKeyFromObject(storeObject), storeObject)
219				if getError == nil {
220					storeResourceVersion = storeObject.GetResourceVersion()
221				} else {
222					logger.Error(getError, "error finding already provisioned resource")
223				}
224			}
225		}
226	
227		return storeResourceVersion != objectResourceVersion
228	}
229	
230	func (h *eventHandler) provisionResource(
231		ctx context.Context,
232		logger logr.Logger,
233		gatewayNSName types.NamespacedName,
234		obj client.Object,
235	) error {
236		resources := h.store.getNginxResourcesForGateway(gatewayNSName)
237		if resources != nil && resources.Gateway != nil {
238			var objects []client.Object
239			var err error
240			resourceName := controller.CreateNginxResourceName(gatewayNSName.Name, h.gcName)
241	
242			// Provision NGINX resources only when listeners are defined on the Gateway (including ListenerSets).
243			if len(resources.Gateway.Listeners) > 0 {
244				objects, err = h.provisioner.buildNginxResourceObjects(
245					resourceName,
246					resources.Gateway.Source,
247					resources.Gateway.EffectiveNginxProxy,
248					resources.Gateway.Listeners,
249				)
250				if err != nil {
251					logger.Error(err, "error building some nginx resources")
252				}
253			}
254	
255			// only provision the object that was updated
256			var objectToProvision client.Object
257			for _, object := range objects {
258				if strings.HasSuffix(object.GetName(), obj.GetName()) && reflect.TypeOf(object) == reflect.TypeOf(obj) {
259					objectToProvision = object
260					break
261				}
262			}
263	
264			if objectToProvision == nil {
265				return nil
266			}
267	
268			if err := h.provisioner.provisionNginx(
269				ctx,
270				resourceName,
271				resources.Gateway.Source,
272				[]client.Object{objectToProvision},
273			); err != nil {
274				return fmt.Errorf("error updating nginx resource: %w", err)
275			}
276		}
277	
278		return nil
279	}
280	
281	// reprovisionResources redeploys nginx resources that have been deleted but should not have been.
282	func (h *eventHandler) reprovisionResources(ctx context.Context, event *events.DeleteEvent) error {
283		gateway := h.store.gatewayExistsForResource(event.Type, event.NamespacedName)
284	
285		if gateway != nil {
286			gatewayNsName := types.NamespacedName{
287				Namespace: gateway.Source.Namespace,
288				Name:      gateway.Source.Name,
289			}
290	
291			if gateway.Valid && !h.store.isGatewayDeleting(gatewayNsName) {
292				resourceName := controller.CreateNginxResourceName(gateway.Source.GetName(), h.gcName)
293				if err := h.provisioner.reprovisionNginx(
294					ctx,
295					resourceName,
296					gateway.Source,
297					gateway.EffectiveNginxProxy,
298					gateway.Listeners,
299				); err != nil {
300					return err
301				}
302			}
303		}
304	
305		return nil
306	}
307	
308	// provisionResourceForAllGateways is called when a resource is updated that needs to be applied
309	// to all Gateway deployments. For example, NGINX Plus secrets.
310	func (h *eventHandler) provisionResourceForAllGateways(
311		ctx context.Context,
312		logger logr.Logger,
313		obj client.Object,
314	) error {
315		var allErrs []error
316		gateways := h.store.getGateways()
317		for gateway := range gateways {
318			if err := h.provisionResource(ctx, logger, gateway, obj); err != nil {
319				allErrs = append(allErrs, err)
320			}
321		}
322	
323		return errors.Join(allErrs...)
324	}
325	
326	// deprovisionSecretsForAllGateways cleans up any secrets that a user deleted that were duplicated
327	// for all Gateways. For example, NGINX Plus secrets.
328	func (h *eventHandler) deprovisionSecretsForAllGateways(ctx context.Context, secret string) error {
329		var allErrs []error
330	
331		for gateway := range h.store.getGateways() {
332			resources := h.store.getNginxResourcesForGateway(gateway)
333			if resources == nil {
334				continue
335			}
336	
337			allErrs = append(allErrs, h.deprovisionMatchingSecrets(ctx, resources, secret)...)
338		}
339	
340		return errors.Join(allErrs...)
341	}
342	
343	// deprovisionMatchingSecrets deletes the duplicated secrets for a single Gateway whose names match the
344	// deleted user secret. The named secrets are checked in priority order and only the first match is
345	// deprovisioned; if none match, the duplicated docker registry secrets are checked instead.
346	func (h *eventHandler) deprovisionMatchingSecrets(
347		ctx context.Context,
348		resources *NginxResources,
349		secret string,
350	) []error {
351		namedSecrets := []metav1.ObjectMeta{
352			resources.AgentTLSSecret,
353			resources.PlusJWTSecret,
354			resources.PlusCASecret,
355			resources.PlusClientSSLSecret,
356			resources.DataplaneKeySecret,
357		}
358	
359		for _, meta := range namedSecrets {
360			if strings.HasSuffix(meta.Name, secret) {
361				if err := h.provisioner.deleteObject(ctx, &corev1.Secret{ObjectMeta: meta}); err != nil {
362					return []error{err}
363				}
364				return nil
365			}
366		}
367	
368		var errs []error
369		for _, dockerSecret := range resources.DockerSecrets {
370			if strings.HasSuffix(dockerSecret.Name, secret) {
371				if err := h.provisioner.deleteObject(ctx, &corev1.Secret{ObjectMeta: dockerSecret}); err != nil {
372					errs = append(errs, err)
373				}
374			}
375		}
376	
377		return errs
378	}
