func (h *eventHandlerImpl) sendNginxConfig(ctx context.Context, logger logr.Logger, gr *graph.Graph) {
	if gr == nil {
		return
	}

	// Reconcile WAF bundle pollers on every graph update, regardless of Gateway state.
	// This ensures pollers for deleted or orphaned policies are stopped even on early returns.
	defer h.reconcileWAFPollers(ctx, gr)

	h.reconcileAPResourceFinalizers(ctx, logger, gr)

	if len(gr.Gateways) == 0 {
		// still need to update GatewayClass status
		obj := &status.QueueObject{
			UpdateType: status.UpdateAll,
		}
		h.cfg.statusQueue.Enqueue(obj)
		return
	}

	// ensure headless "shadow" Services are created for any referenced InferencePools
	h.ensureInferencePoolServices(ctx, gr.ReferencedInferencePools)

	for _, gw := range gr.Gateways {
		go func() {
			if err := h.cfg.nginxProvisioner.RegisterGateway(ctx, gw, gw.DeploymentName.Name); err != nil {
				logger.Error(err, "error from provisioner")
			}
		}()

		// If no listeners or invalid, update status but skip config generation
		if len(gw.Listeners) == 0 || !gw.Valid {
			obj := &status.QueueObject{
				Deployment: status.Deployment{
					NamespacedName: gw.DeploymentName,
					GatewayName:    gw.Source.GetName(),
				},
				UpdateType: status.UpdateAll,
			}
			h.cfg.statusQueue.Enqueue(obj)
			continue
		}

		if gatewayHasPendingWAFBundle(gr, gw) && !graph.WAFBundleFailOpenForNginxProxy(gw.EffectiveNginxProxy) {
			// Fail-closed (default): a pending bundle blocks the config push until the bundle is available.
			// Enqueue a status update because the config is being withheld in this fail-closed case,
			// making the pending condition visible to the operator.
			obj := &status.QueueObject{
				UpdateType: status.UpdateAll,
				Deployment: status.Deployment{
					NamespacedName: gw.DeploymentName,
					GatewayName:    gw.Source.GetName(),
				},
				Error: errors.New("NGINX configuration update withheld: WAF bundle for Gateway is still pending"),
			}
			h.cfg.statusQueue.Enqueue(obj)
			continue
		}

package controller

import (
	"crypto/sha256"
	"encoding/hex"
	"strings"
)

const (
	// inferencePoolServiceSuffix is the suffix of the headless Service name for an InferencePool.
	inferencePoolServiceSuffix = "pool-svc"
	MaxServiceNameLen          = 63
	hashLen                    = 8
)

// CreateNginxResourceName creates the base resource name for all nginx resources
// created by the control plane.
func CreateNginxResourceName(prefix, suffix string) string {
	return truncateAndHashName(prefix, suffix)
}

// CreateInferencePoolServiceName creates the name for a headless Service that
// we create for an InferencePool.
func CreateInferencePoolServiceName(name string) string {
	return truncateAndHashName(name, inferencePoolServiceSuffix)
}

// truncateAndHashName truncates the input name to fit within maxLen,
// appending a hash for uniqueness if needed.
func truncateAndHashName(name string, suffix string) string {
	sep := "-"
	full := name + sep + suffix
	if len(full) <= MaxServiceNameLen {
		return full
	}

	// Always include the suffix, truncate name as needed
	hash := sha256.Sum256([]byte(full))
	hashStr := hex.EncodeToString(hash[:])[:hashLen]
	maxNameLen := MaxServiceNameLen - (len(sep) * 2) - hashLen - len(suffix)
	truncName := name
	if len(name) > maxNameLen {
		truncName = name[:maxNameLen]
	}

	// Remove trailing dashes to avoid double-dash when separator is added
	truncName = strings.TrimRight(truncName, sep)

	return truncName + sep + hashStr + sep + suffix
}

